    input.push(line);
}).on('close', function() {
    let [n, m] = input[0].split(' ').map(Number);
    let a = [];
    for (let i = 1; i <= n; i++) {
        a.push(input[i].split('').map(Number));
    }
    let max = 0;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            for (let k = i; k < n; k++) {
                for (let l = j; l < m; l++) {
                    let sum = 0;
                    for (let x = i; x <= k; x++) {
                        for (let y = j; y <= l; y++) {
                            sum += a[x][y];
                        }
                    }
                    max = Math.max(sum, max);
                }
            }
        }
    }
    console.log(max);
});
